+// Check if folding a select with an ordered floating-point comparison condition
+// is safe. This is unsafe when TrueVal contains operations that can produce
+// poison for the same inputs that make CondVal false (e.g., NaN inputs).
+static bool isSafeToFoldSelectWithOrderedFPComparison(const Value *CondVal,
+                                                      const Value *TrueVal) {
+  // Check if CondVal is an ordered floating-point comparison
+  auto *FCmp = dyn_cast<FCmpInst>(CondVal);
+  if (!FCmp || FCmp->getPredicate() != FCmpInst::FCMP_ORD)
+    return true;
+
+  // If TrueVal might produce poison when the operands of FCmp are NaN,
+  // then this transformation is unsafe.
+  // We conservatively check if TrueVal contains any instructions that
+  // could be affected by fast-math flags or produce poison from floating-point
+  // operations.
+  
+  // For now, we use a simple heuristic: if TrueVal is not a constant and
+  // depends on floating-point values, be conservative.
+  // A more precise analysis would require dataflow analysis to check
+  // if TrueVal and CondVal share common floating-point operands.
+  
+  // Check if TrueVal contains any instructions that could produce poison
+  // due to fast-math flags when the input is NaN.
+  SmallPtrSet<const Value *, 8> Visited;
+  SmallVector<const Value *, 8> Worklist;
+  Worklist.push_back(TrueVal);
+  
+  while (!Worklist.empty()) {
+    const Value *V = Worklist.pop_back_val();
+    if (!Visited.insert(V).second)
+      continue;
+      
+    if (const auto *I = dyn_cast<Instruction>(V)) {
+      // Check for calls with nnan attribute
+      if (const auto *CB = dyn_cast<CallBase>(I)) {
+        if (CB->hasFnAttr(Attribute::NoNaNs))
+          return false;
+        if (CB->hasRetAttr(Attribute::NoNaNs))
+          return false;
+      }
+      
+      // Check for floating-point instructions with nnan fast-math flag
+      if (isa<FPMathOperator>(I)) {
+        if (I->hasNoNaNs())
+          return false;
+      }
+      
+      // Add operands to worklist
+      for (const Use &U : I->operands()) {
+        Worklist.push_back(U.get());
+      }
+    }
+  }
+  
+  return true;
+}
